module gray_counter_3bit(
    input clk,
    input rst,
    output [2:0] count
);

    reg [2:0] obf_counter_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_counter_reg <= 3'b000;
        end else begin
            obf_counter_reg <= obf_counter_reg + 1;
        end
    end

    assign count = obf_counter_reg ^ (obf_counter_reg >> 1);

endmodule
